const sellerData = items.map(item => item.json);
const itemSellers = $('Get Item Sellers').all().map(i => i.json.results).flat();

const active = sellerData.filter(s => s.status?.site_status === 'active');

const scored = active.map(s => {
  const rep = s.seller_reputation;
  const levelScore = {'5_green':5,'4_light_green':4,'3_yellow':3,'2_orange':2,'1_red':1}[rep?.level_id] || 0;
  const powerScore = rep?.power_seller_status ? 1 : 0;
  const salesScore = rep?.transactions?.completed || 0;
  const itemId = itemSellers.find(is => is.seller_id == s.id)?.item_id;
  return { ...s, item_id: itemId, score: (levelScore * 1000) + (powerScore * 500) + salesScore };
});

scored.sort((a, b) => b.score - a.score);
return [{ json: scored[0] }];

