  json: {
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      messages: [{ role: "user", content: prompt }],
      temperature: 0.2,
      response_format: {
        type: "json_schema",
        json_schema: { name: "review_output", strict: true, schema: jsonSchema }
      }
    })
  }
}];

// Gemini ya emite articulo_html directamente. Solo desescapamos y limpiamos.
let html = ($('Parse Gemini JSON').first().json.articulo_html || '').toString();
html = html.replace(/\\n/g, '\n').replace(/\\t/g, '').trim();
// Sacar h2/h3 que Gemini metio dentro de un p
html = html
  .replace(/<p>\s*(<h[1-6][^>]*>)/gi, '$1')
  .replace(/(<\/h[1-6]>)\s*<\/p>/gi, '$1');
return [{ json: { html } }];

const raw = $input.first().json.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Abacus parse error: ' + e.message + ' | Raw: ' + raw.substring(0, 200));
}
return [{ json: parsed }];

const item = $('Get Data ML').first().json;
const parsedGemini = $('Parse Gemini JSON').first().json;
const htmlNode = $('Convert to HTML').first().json;
const bestSeller = $('Pick Best Seller').first().json;
const reviews = $('Get Reviews ML').first().json;
const videos = $('Top videos').first().json.items;

// Precio
let precioActual = null, precioOriginal = null, descuentoPct = 0, garantia = null, envioGratis = false;
try {
  const sellers = $('Get Item Sellers').first().json.results;
  const sellerItem = sellers.find(s => s.item_id === bestSeller.item_id) || sellers[0];
  precioActual = sellerItem.price;
  precioOriginal = sellerItem.original_price || sellerItem.price;
  descuentoPct = precioOriginal > precioActual ? Math.round((1 - precioActual / precioOriginal) * 100) : 0;
  garantia = sellerItem.warranty;
  envioGratis = sellerItem.shipping?.free_shipping || false;
} catch(e) {}

// Specs
const specs = {};
for (const attr of item.attributes) specs[attr.name] = attr.value_name;

// ?? SLUG LIMPIO ????????????????????????????????????????????????????????????
// Usa Marca + Modelo (si es texto, no c?digo) + L?nea + Submodelo
// Evita specs num?ricas, colores, condiciones y palabras gen?ricas del nombre
const getAttr = (n) => (item.attributes.find(a => a.name === n) || {}).value_name || '';
const slugify = (s) => (s || '').toLowerCase()
  .normalize('NFD').replace(/[̀-ͯ]/g, '')
  .replace(/[^a-z0-9\s]/g, '').trim()
  .replace(/\s+/g, '-');
// Detecta c?digos alfanum?ricos de modelo (ej: X1607CA, 890101-0100)
// Sin flag 'i' para que "Switch", "OLED", "Ultra" no sean tratados como c?digos
const isCode = (s) => Boolean(s && ((/\d/.test(s) && /-/.test(s)) || /^[A-Z0-9]{5,}$/.test(s)));
const isMeaningful = (s) => Boolean(s && s.length > 2 && !/^\d+$/.test(s) && !isCode(s));

const marca     = getAttr('Marca');
const modelo    = getAttr('Modelo');
const submodelo = getAttr('Submodelo');
const linea     = getAttr('L?nea');

const slugParts = [marca];

// Modelo solo si es texto legible (Switch, Pro, Air...) no un c?digo alfanum?rico
if (isMeaningful(modelo) && slugify(modelo) !== slugify(marca)) {
  slugParts.push(modelo);
}

// L?nea: primeras 2 palabras significativas (sin "Generaci?n", "Gen")
if (linea) {
  const cleanWords = linea.split(/\s+/)
    .filter(w => isMeaningful(w) && !/^(generaci[o?]n|gen)$/i.test(w))
    .slice(0, 2);
  slugParts.push(...cleanWords);
}

// Submodelo si es legible (OLED, Pro, Air, Ultra...) no un c?digo
if (isMeaningful(submodelo) && !isCode(submodelo)) {
  slugParts.push(submodelo);
}

// Si sigue siendo muy corto, agregar palabras clave del nombre del producto
const noiseWords = new Set([
  'laptop','notebook','consola','audifonos','auriculares','headphones',
  'con','y','de','la','el','para','un','una','los','las',
  'gb','tb','ssd','hdd','ram','mhz','ghz','fps','hz',
  'nuevo','reacondicionado','excelente','bueno','muy',
  'negro','blanco','rojo','azul','dorado','plateado','neon','silver','gold',
  'mochila','mouse','incluye','incluido','kit','combo',
  'inalambrico','bluetooth','wifi','usb','hdmi','type',
  'gen','generacion','edicion','edition','series','version',
  'gaming','gamer','pro','plus','max','mini','lite','air',
  'ultrabook','slim','thin','portable',
]);

if (slugParts.filter(Boolean).length < 3) {
  const nameWords = item.name.toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s]/g, '').split(/\s+/)
    .filter(w => w.length > 2 && !/^\d/.test(w) && !noiseWords.has(w));

  // Separar "switch-2" en ["switch","2"] para detectar duplicados correctamente
  const existing = new Set(slugParts.map(p => slugify(p)).flatMap(s => s.split('-')).filter(Boolean));
  for (const w of nameWords) {
    if (!existing.has(w) && slugParts.length < 5) {
      slugParts.push(w);
      existing.add(w);
    }
  }
}

const slug = slugParts
  .filter(Boolean)
  .map(slugify)
  .join('-')
  .replace(/-+/g, '-')
  .slice(0, 60);

// ?? OPINIONES DESTACADAS ???????????????????????????????????????????????????
// Solo mostrar si hay reviews reales de compradores en ML.
// Si no hay (total=0), Gemini las inventa de los videos ? misleading ? vaciar.
const totalReviews = reviews.paging.total;
const reviewsDestacadas = totalReviews > 0
  ? (parsedGemini.opiniones_destacadas || []).map(o => ({
      titulo:     o.aspecto,
      contenido:  o.resumen,
      sentimiento: o.sentimiento || 'mixto',
    }))
  : [];

// Videos
const videosYT = videos.map(v => ({
  video_id:  v.id.videoId,
  titulo:    v.snippet.title,
  canal:     v.snippet.channelTitle,
  url:       `https://www.youtube.com/watch?v=${v.id.videoId}`,
  thumbnail: v.snippet.thumbnails.high.url,
  publicado: v.snippet.publishedAt.split('T')[0],
  vistas:    parseInt(v.statistics?.viewCount || '0', 10),
}));

const numVids = $('Transcripciones').first().json.num_videos_con_transcripcion;

return [{ json: {
  meta: {
    producto_id: item.id,
    slug,
    categoria: item.domain_id,
    generado_en: new Date().toISOString(),
  },
  producto: {
    nombre:   item.name,
    marca:    specs['Marca'] || null,
    modelo:   specs['Modelo'] || null,
    descripcion: item.short_description.content,
    caracteristicas_principales: item.main_features.map(f => f.text.trim()),
    specs,
    imagenes: item.pictures.map(p => p.url),
  },
  precio: {
    actual:        precioActual,
    original:      precioOriginal,
    descuento_pct: descuentoPct,
    moneda:        'MXN',
    envio_gratis:  envioGratis,
    garantia,
  },
  vendedor: {
    item_id:      bestSeller.item_id,
    nombre:       bestSeller.nickname,
    reputacion:   bestSeller.seller_reputation?.level_id || null,
    power_seller: bestSeller.seller_reputation?.power_seller_status || null,
    transacciones: bestSeller.seller_reputation?.transactions?.total || null,
  },
  link_afiliado: ($('Route Row').first().json.referido || null),
  reviews_ml: {
    total:                totalReviews,
    con_comentario:       reviews.paging.reviews_with_comment,
    calificacion_promedio: reviews.rating_average,
    destacadas:           reviewsDestacadas,
  },
  videos_yt: videosYT,
  editorial: {
    score:             parsedGemini.editorial_score,
    score_justificacion: parsedGemini.score_justificacion || null,
    sub_scores:        parsedGemini.sub_scores || [],
    veredicto_corto:   parsedGemini.veredicto_corto || parsedGemini.seo_description,
    compralo_si:       parsedGemini.compralo_si || [],
    saltatelo_si:      parsedGemini.saltatelo_si || [],
    pros:              parsedGemini.pros || [],
    contras:           parsedGemini.contras || [],
    fuentes_citadas:   parsedGemini.fuentes_citadas || [],
    faq:           parsedGemini.faq || [],
    precio_valor:  parsedGemini.precio_valor || null,
    alternativas:  parsedGemini.alternativas || [],
    seo_title:         parsedGemini.seo_title,
    seo_description:   parsedGemini.seo_description,
    articulo_html:     htmlNode.html,
  },
  productos_similares_ml: (() => {
    try {
      const currentId = $('Get Data ML').first().json.id;
      return ($('Get Similar Products').first().json.results || [])
        .filter(it => it.id !== currentId && it.title && it.price)
        .slice(0, 5)
        .map(it => ({
          id:             it.id,
          titulo:         it.title,
          precio:         it.price,
          precio_original: it.original_price || it.price,
          thumbnail:      it.thumbnail ? it.thumbnail.replace('http://', 'https://') : null,
          permalink:      it.permalink,
          envio_gratis:   it.shipping?.free_shipping || false,
        }));
    } catch(e) { return []; }
  })(),
  autoria: {
    nombre:    'Hito Flores',
    tagline:   'An?lisis independiente de productos en Mercado Libre M?xico',
    metodologia: (() => {
      // Detectar si los videos son del modelo exacto o de modelos similares
      const prodTokens = [getAttr('Submodelo'), modelo, linea.split(' ')[0]]
        .filter(t => t && t.length > 2 && !isCode(t))
        .map(t => t.toLowerCase());
      const esSimilar = videosYT.length > 0 && prodTokens.length > 0 &&
        !videosYT.some(v => prodTokens.some(t => v.titulo.toLowerCase().includes(t)));
      const lineaCorta = [marca, linea.split(' ').slice(0,2).join(' ')].filter(Boolean).join(' ').trim();
      return esSimilar
        ? `Este an?lisis sintetiza ${numVids} rese?as de modelos similares de la l?nea ${lineaCorta} y ${totalReviews} opiniones de compradores verificados de Mercado Libre.`
        : `Este an?lisis sintetiza ${numVids} rese?as en video de creadores independientes y ${totalReviews} opiniones de compradores verificados de Mercado Libre.`;
    })(),
    actualizado: new Date().toISOString().slice(0, 10),
  },
}}];

const data = $('Build Final JSON').first().json;
const sha = $('GitHub GET SHA').first().json?.sha || undefined;
const content = Buffer.from(JSON.stringify(data, null, 2)).toString('base64');

const body = { message: `feat: review ${data.meta.slug}`, content };
if (sha) body.sha = sha;

const result = await this.helpers.httpRequest({
  method: 'PUT',
  url: `https://api.github.com/repos/HitoFlores/AfiliadosML/contents/data/${data.meta.slug}.json`,
  headers: {
    'Authorization': 'Bearer ' + $env.GITHUB_TOKEN,
    'Accept': 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(body)
});

return [{ json: result }];

// Top videos v2: marca requerida + prioriza reviews reales sobre gameplay/tests destructivos
const API_KEY = $env.YOUTUBE_API_KEY;

const attrs = $('Get Data ML').first().json.attributes || [];
const getAttr = (n) => (attrs.find((a) => a.name === n) || {}).value_name || '';

const marca     = getAttr('Marca').toLowerCase().trim();
const submodelo = getAttr('Submodelo').toLowerCase().trim();
const modelo    = getAttr('Modelo').toLowerCase().trim();
const linea     = getAttr('Linea')
  .replace(/Generacion/gi, '').replace(/Gen/gi, '').replace(/\d+/g, '').toLowerCase().trim();

const isCode = (s) => Boolean(s && s.match(/\d/) && s.match(/-/));

const relevanceTokens = [
  submodelo && !isCode(submodelo) ? submodelo : null,
  !isCode(modelo) && modelo !== marca ? modelo.split(' ')[0] : null,
  linea ? linea.split(/\s+/).find(w => w.length > 2) || null : null,
].filter(Boolean);

const search = $('Get Videos YT').first().json.items || [];

// Terminos que indican review/analisis real (el tipo de contenido que queremos)
const REVIEW_TERMS = [
  'review', 'analisis', 'an?lisis', 'rese?a', 'resena',
  'vale la pena', 'hands on', 'comparativa', 'comparacion', 'comparaci?n',
  'opinion', 'opini?n', 'should you buy', 'is it worth', 'first look',
  'unboxing', 'vs ', ' vs', 'overview', 'prueba', 'test de',
];

// Terminos que indican contenido NO-review (gameplay, tests destructivos, entretenimiento)
const NON_REVIEW_TERMS = [
  'gameplay', 'playthrough', "let's play", 'lets play',
  'scratch test', 'drop test', 'bend test', 'durability test',
  'teardown', 'tear down', 'disassembly', 'water test',
  'torture test', 'speed test', 'speed run',
  'relaxing', 'asmr', 'satisfying', 'satisfaccion',
  'partida', 'walkthrough', 'longplay', 'full game',
  'highlights', 'shorts',
];

const scored = search.map((v) => {
  const title   = (v.snippet.title || '').toLowerCase();
  const fullTxt = title + ' ' + (v.snippet.description || '').toLowerCase();

  // La marca DEBE aparecer en titulo o descripcion
  if (!fullTxt.includes(marca)) return null;

  // +N por tokens del producto en el titulo
  const productBonus = relevanceTokens.filter(t => title.includes(t)).length;

  // +2 si el titulo contiene terminos de review real
  // -2 si contiene terminos de contenido no-review
  const isReview    = REVIEW_TERMS.some(t => title.includes(t));
  const isNonReview = NON_REVIEW_TERMS.some(t => title.includes(t));
  const reviewBonus = isReview ? 2 : (isNonReview ? -2 : 0);

  return {
    ...v,
    _relevance:   productBonus,
    _reviewBonus: reviewBonus,
    _total:       productBonus + reviewBonus,
  };
}).filter(Boolean);

// Fallback si ningun video menciona la marca
const pool = scored.length
  ? scored
  : search.map(v => ({ ...v, _relevance: 0, _reviewBonus: 0, _total: 0 }));

const ids = pool.map((v) => v.id && v.id.videoId).filter(Boolean);
const stats = {};
if (ids.length) {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: { part: 'statistics', id: ids.join(','), key: API_KEY },
    json: true,
  });
  for (const it of (res.items || [])) stats[it.id] = it.statistics || {};
}

const ranked = pool
  .map((v) => {
    const st = stats[v.id.videoId] || {};
    return { ...v, statistics: st, _views: parseInt(st.viewCount || '0', 10) };
  })
  .sort((a, b) => {
    // 1ro: score total (relevancia de producto + bonus review)
    // 2do: vistas (solo como desempate entre videos del mismo score)
    if (b._total !== a._total) return b._total - a._total;
    return b._views - a._views;
  })
  .slice(0, 3);

return [{ json: { items: ranked } }];

// Transcripciones - baja los subt?tulos de los top videos v?a Supadata
const API_KEY = $env.SUPADATA_API_KEY; // variable de entorno (no hardcodeada)
const videos = $('Top videos').first().json.items || [];

const partes = [];
let conTranscripcion = 0;

for (let i = 0; i < videos.length; i++) {
  const v = videos[i].snippet || {};
  const id = videos[i].id.videoId;
  let transcript = '';
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.supadata.ai/v1/youtube/transcript',
      qs: { videoId: id, text: 'true', lang: 'es' },
      headers: { 'x-api-key': API_KEY },
      json: true,
    });
    transcript = (res.content || '').toString().slice(0, 6000); // cap tokens
  } catch (e) {
    transcript = ''; // sin subt?tulos -> seguimos sin romper
  }
  if (transcript) conTranscripcion++;
  const cuerpo = transcript
    ? transcript
    : `(sin transcripci?n disponible) Descripci?n: ${v.description || 'n/d'}`;
  partes.push(
    `VIDEO ${i + 1}\nCANAL: ${v.channelTitle}\nT?TULO: ${v.title}\nCONTENIDO: ${cuerpo}`
  );
}

return [{ json: {
  bloque_videos: partes.join('\n\n---\n\n'),
  num_videos_con_transcripcion: conTranscripcion
}}];

// Route Row: elige la fila a procesar.
// Si el articulo es meli.la/xxx, resuelve el link social de ML para extraer el MLM catalog ID.
const rows = $('Get Queue').all().map((i) => i.json);
const norm = (s) => (s || '').toString().trim().toLowerCase();

const pick =
  rows.find((r) => norm(r.estatus) === 'ready') ||
  rows.find((r) => norm(r.estatus) === 'pending');

if (!pick) return [];

let link    = (pick.articulo || '').toString();
let product_id = '';

// ?? Caso 1: link corto meli.la ? resolver pagina social de ML ??????????????
if (link.includes('meli.la/')) {
  try {
    // Paso 1: seguir el redirect de meli.la ? llega a /social/rulloco?...
    const r1 = await this.helpers.httpRequest({
      method: 'GET', url: link,
      followRedirects: true, returnFullResponse: true, ignoreResponseCode: true,
    });
    const socialUrl = r1.requestOptions?.uri?.href || link;

    // Paso 2: si llego a /social/..., bajar la pagina y extraer el primer MLM ID
    if (socialUrl.includes('mercadolibre')) {
      const r2 = await this.helpers.httpRequest({
        method: 'GET', url: socialUrl,
        followRedirects: true, ignoreResponseCode: true,
      });
      const html = typeof r2 === 'string' ? r2 : JSON.stringify(r2);

      // El primer MLM ID en el HTML es el producto destacado (featured card)
      const firstMlm = html.match(/MLM[0-9]{6,}/);
      if (firstMlm) {
        product_id = firstMlm[0].toUpperCase();
        link = 'https://www.mercadolibre.com.mx/p/' + product_id;
      }
    }
  } catch(e) {
    // Si falla la resolucion, product_id queda vacio y el pipeline lo manejara
  }
}

// ?? Caso 2: link directo con MLM en la URL ??????????????????????????????????
if (!product_id) {
  const m = link.match(/\/p\/(ML[A-Z]?[0-9]+)/i) || link.match(/(ML[A-Z][0-9]{6,})/i);
  product_id = m ? m[1].toUpperCase() : '';
}

const estatus = norm(pick.estatus);
return [{
  json: {
    _pass:      estatus === 'ready' ? 'pass2' : 'pass1',
    row_number: pick.row_number,
    product_id,
    articulo:   link,
    referido:   (pick.referido || '').toString(),
    idioma:     ((pick.idioma || 'es').toString().trim() || 'es').toLowerCase(),
  },
}];

// Pass 1: arma el link del ?tem del mejor vendedor verde para que el due?o
// genere el referido manualmente.
const best = $('Pick Best Seller').first().json;
const itemId = (best.item_id || '').toString();

// item_id "MLM1234567890" -> URL "MLM-1234567890"
let link = '';
if (itemId) {
  const dashed = itemId.replace(/^(ML[A-Z])/i, '$1-');
  link = `https://articulo.mercadolibre.com.mx/${dashed}`;
}

return [{
  json: {
    link_sugerido: link,
    vendedor: best.nickname || '',
    reputacion: best.seller_reputation?.level_id || '',
  },
}];

